var e=[{id:`L3_1`,type:`dialog`,speaker:`SILKY_NPC_ESPR2_NULL`,text:{KOREA:`부학회장님, 저 괴물은 대체…….`,JPN:`副学会長様、あの怪物はいったい……`,ENG:`Vice President, what is that thing...?`,TWN:`副學會長，那個怪物究竟……`},stage:{bg:`CORRIDOR_06`,slots:{L:{char_id:`SILKY_NPC_ESPR2_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L5_1`,type:`dialog`,speaker:`CHASER_NPC_ESPR2_NULL`,text:{KOREA:`<color=#ff3636>레지. 나.</color>`,JPN:`<color=#ff3636>レジー、ナ。</color>`,ENG:`<color=#ff3636>Regi. Na.</color>`,TWN:`<color=#ff3636>蕾·佳·娜。</color>`},stage:{bg:`CORRIDOR_06`,slots:{L:null,C:{char_id:`CHASER_NPC_ESPR2_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`SILKY_NPC_ESPR2_NULL`,text:{KOREA:`부학회장님! 괴물이 다가와요! 정신 차리세요!`,JPN:`副学会長様！　怪物が近づいてきます！　お気を確かに！`,ENG:`Vice President! It's coming this way! Run!`,TWN:`副學會長！怪物過來了！你醒醒啊！`},stage:{bg:`CORRIDOR_06`,slots:{L:null,C:{char_id:`SILKY_NPC_ESPR2_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`하아……. 하…… 하아…….`,JPN:`はあ……は……はあ……`,ENG:`*Huff...* *Huff...* *Huff...*`,TWN:`呼呼……呼……呼呼……`},stage:{bg:`CORRIDOR_06`,slots:{L:null,C:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`안 돼. 손가락 하나 까딱 못하겠어.`,JPN:`ダメ。指ひとつ動かせないわ。`,ENG:`Why... Why can I not move...?`,TWN:`不行。手指動不了了。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`침식체도, 잔해도 아무렇지 않았는데…… 저건 어디서 나타난 괴물이지?`,JPN:`侵食体でも、残骸でも何ともなかったのに……あれはどこから来た怪物なの？`,ENG:`I was not like this when I encountered a C.O. or the Remains... But where did that monster even come from?`,TWN:`既不是侵蝕體，也不是殘骸……那東西究竟是從哪裡來的怪物？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`움직여야 돼. 움직이지 않으면 죽어.`,JPN:`動かないと。動かないと死ぬ。`,ENG:`Please move... If I do not, I will die.`,TWN:`必須動起來。不動就得死。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`하지만 움직인다고 뭐가 달라질까? 저런 것에게서 내가 도망칠 수 있을까?`,JPN:`でも動けたとして何ができるの？　あんな怪物から逃げられるとでも？`,ENG:`But will it change anything? Will I be able to run away from it?`,TWN:`可是就算能動，又有什麼區別呢？我能從那東西手中逃脫嗎？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`……살아나갈 수가, 있을까?`,JPN:`……生きて出られる、かしら？`,ENG:`Will I... be able to make it out alive?`,TWN:`……我能，活下去嗎？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`CHASER_NPC_ESPR2_NULL`,text:{KOREA:`<color=#ff3636>아아아아……!! </color>`,JPN:`<color=#ff3636>アアアア……！！</color>`,ENG:`<color=#ff3636>Ahhhh...!!</color>`,TWN:`<color=#ff3636>啊啊啊啊……！！</color>`},stage:{bg:`CORRIDOR_06`,slots:{L:null,C:{char_id:`CHASER_NPC_ESPR2_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`TRUMPET_HARMONY_ESPR2_NULL`,text:{KOREA:`다들 지금이야! 한눈 팔고 있는 사이에 혼쭐을 내 주자!`,JPN:`みんな、今だよ！　よそ見をしている間にやってしまえ！`,ENG:`NOW! Give it hell while it's distracted!`,TWN:`就是現在！趁著它分神，好好教訓它吧！`},stage:{bg:`CORRIDOR_06`,slots:{L:null,C:{char_id:`TRUMPET_HARMONY_ESPR2_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`DOCTOR_NPC_ESPR2_NULL`,text:{KOREA:`총알이…… 공중에서 멈춰 버린다고?`,JPN:`銃弾が……空中で止まるだと？`,ENG:`The bullets... It stopped them mid-air?!`,TWN:`子彈……停在空中了？`},stage:{bg:`CORRIDOR_06`,slots:{L:null,C:null,R:{char_id:`DOCTOR_NPC_ESPR2_NULL`,face:`UNIT_IDLE`}}}},{id:`L26_1`,type:`dialog`,speaker:`DOCTOR_NPC_ESPR2_NULL`,text:{KOREA:`대체 무슨 침식체지? 생포해서 연구해야 할 텐데!`,JPN:`いったいどんな侵食体なんだ？　生け捕りにして研究しなければ！`,ENG:`What kind of C.O. is it? We should capture it and research it!`,TWN:`究竟是什麼侵蝕體呢？應該活捉研究一下！`},stage:{bg:`CORRIDOR_06`,slots:{L:{char_id:`DOCTOR_NPC_ESPR2_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L28_1`,type:`dialog`,speaker:`TRUMPET_HARMONY_ESPR2_NULL`,text:{KOREA:`치이……. 귀찮은 녀석이네.`,JPN:`ちいっ……めんどくさいやつ。`,ENG:`Tch...! This isn't good.`,TWN:`嘖……真是個麻煩的傢伙。`},stage:{bg:`CORRIDOR_06`,slots:{L:null,C:{char_id:`TRUMPET_HARMONY_ESPR2_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`TRUMPET_HARMONY_ESPR2_NULL`,text:{KOREA:`앗, 부학회장이다! 쟨 또 왜 방에서 기어나와 있어?!`,JPN:`あっ、副学会長！　ったく、なんでまた部屋から抜け出してるんだよ！？`,ENG:`Huh? It's the Vice President! Why did she even leave her room again?!`,TWN:`啊，是副學會長！她怎麼又從房間裡跑出來了？！`},stage:{bg:`CORRIDOR_06`,slots:{L:null,C:{char_id:`TRUMPET_HARMONY_ESPR2_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`아…….`,JPN:`あ……`,ENG:`Oh...`,TWN:`啊……`},stage:{bg:`CORRIDOR_06`,slots:{L:null,C:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};